# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from threading import Lock
import uuid
import os
import json
import numpy as np

try:
    import tensorflow as tf
except Exception:
    tf = None

app = Flask(__name__)

DATA_DIR = os.environ.get("LABEL_DATA_DIR", "label_data")
MODEL_DIR = os.environ.get("MODEL_DIR", "trained_model")
os.makedirs(DATA_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

lock = Lock()

images = {}
annotations = defaultdict(list)
aggregated_labels = {}
model = None


def _save_json(path, obj):
    with open(path, "w", encoding="utf-8") as f:
        json.dump(obj, f, ensure_ascii=False, indent=2)


def _load_json(path, default):
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    return default


def _persist_state():
    _save_json(os.path.join(DATA_DIR, "images.json"), images)
    _save_json(os.path.join(DATA_DIR, "annotations.json"), dict(annotations))
    _save_json(os.path.join(DATA_DIR, "aggregated_labels.json"), aggregated_labels)


def _load_state():
    global images, annotations, aggregated_labels
    images = _load_json(os.path.join(DATA_DIR, "images.json"), {})
    annotations = defaultdict(list, _load_json(os.path.join(DATA_DIR, "annotations.json"), {}))
    aggregated_labels = _load_json(os.path.join(DATA_DIR, "aggregated_labels.json"), {})


def majority_vote(labels):
    if not labels:
        return None
    counts = Counter(labels)
    top = counts.most_common()
    if len(top) == 1:
        return top[0][0]
    if top[0][1] == top[1][1]:
        tied = [label for label, count in top if count == top[0][1]]
        return sorted(tied)[0]
    return top[0][0]


def aggregate_image(image_id):
    labels = [a["label"] for a in annotations.get(image_id, []) if "label" in a]
    agg = majority_vote(labels)
    if agg is not None:
        aggregated_labels[image_id] = agg
    else:
        aggregated_labels.pop(image_id, None)
    _persist_state()
    return agg


def _build_model(num_classes, input_shape):
    if tf is None:
        raise RuntimeError("TensorFlow is not available")
    base = tf.keras.applications.MobileNetV2(
        input_shape=input_shape,
        include_top=False,
        weights=None,
        pooling="avg",
    )
    x = tf.keras.layers.Dense(128, activation="relu")(base.output)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    m = tf.keras.Model(inputs=base.input, outputs=outputs)
    m.compile(optimizer="adam", loss="sparse_categorical_crossentropy", metrics=["accuracy"])
    return m


def _load_image_array(path, target_size=(224, 224)):
    if tf is None:
        raise RuntimeError("TensorFlow is not available")
    img = tf.keras.utils.load_img(path, target_size=target_size)
    arr = tf.keras.utils.img_to_array(img)
    arr = arr / 255.0
    return arr


def train_model():
    global model
    if tf is None:
        raise RuntimeError("TensorFlow is not available")

    labeled_items = [(img_id, lbl) for img_id, lbl in aggregated_labels.items() if img_id in images]
    if not labeled_items:
        raise ValueError("No labeled data available")

    label_names = sorted({lbl for _, lbl in labeled_items})
    label_to_idx = {lbl: i for i, lbl in enumerate(label_names)}

    X = []
    y = []
    for img_id, lbl in labeled_items:
        path = images[img_id]["path"]
        if not os.path.exists(path):
            continue
        X.append(_load_image_array(path))
        y.append(label_to_idx[lbl])

    if not X:
        raise ValueError("No valid image files found")

    X = np.stack(X, axis=0)
    y = np.array(y, dtype=np.int32)

    model = _build_model(num_classes=len(label_names), input_shape=X.shape[1:])
    model.fit(X, y, epochs=5, batch_size=16, verbose=0)

    model_path = os.path.join(MODEL_DIR, "model.keras")
    labels_path = os.path.join(MODEL_DIR, "labels.json")
    model.save(model_path)
    _save_json(labels_path, {"labels": label_names, "label_to_idx": label_to_idx})
    return {"model_path": model_path, "labels": label_names, "num_samples": int(len(X))}


@app.route("/images", methods=["POST"])
def add_image():
    data = request.get_json(force=True, silent=True) or {}
    path = data.get("path")
    metadata = data.get("metadata", {})
    if not path:
        return jsonify({"error": "path is required"}), 400

    image_id = data.get("image_id") or str(uuid.uuid4())
    with lock:
        images[image_id] = {"path": path, "metadata": metadata}
        _persist_state()
    return jsonify({"image_id": image_id, "path": path, "metadata": metadata}), 201


@app.route("/images", methods=["GET"])
def list_images():
    return jsonify(images)


@app.route("/images/<image_id>", methods=["GET"])
def get_image(image_id):
    item = images.get(image_id)
    if not item:
        return jsonify({"error": "not found"}), 404
    return jsonify({"image_id": image_id, **item})


@app.route("/images/<image_id>/annotations", methods=["POST"])
def add_annotation(image_id):
    if image_id not in images:
        return jsonify({"error": "image not found"}), 404

    data = request.get_json(force=True, silent=True) or {}
    annotator_id = data.get("annotator_id")
    label = data.get("label")
    if not annotator_id or label is None:
        return jsonify({"error": "annotator_id and label are required"}), 400

    annotation = {
        "annotator_id": annotator_id,
        "label": label,
        "timestamp": data.get("timestamp"),
    }

    with lock:
        annotations[image_id].append(annotation)
        agg = aggregate_image(image_id)

    return jsonify({"image_id": image_id, "annotation": annotation, "aggregated_label": agg}), 201


@app.route("/images/<image_id>/annotations", methods=["GET"])
def get_annotations(image_id):
    if image_id not in images:
        return jsonify({"error": "image not found"}), 404
    return jsonify({"image_id": image_id, "annotations": annotations.get(image_id, [])})


@app.route("/images/<image_id>/aggregate", methods=["POST"])
def aggregate_endpoint(image_id):
    if image_id not in images:
        return jsonify({"error": "image not found"}), 404
    with lock:
        agg = aggregate_image(image_id)
    return jsonify({"image_id": image_id, "aggregated_label": agg})


@app.route("/aggregate", methods=["POST"])
def aggregate_all():
    with lock:
        result = {}
        for image_id in images:
            result[image_id] = aggregate_image(image_id)
    return jsonify(result)


@app.route("/labels", methods=["GET"])
def list_labels():
    return jsonify(aggregated_labels)


@app.route("/train", methods=["POST"])
def train_endpoint():
    try:
        with lock:
            result = train_model()
        return jsonify(result), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/model", methods=["GET"])
def model_status():
    return jsonify({"trained": model is not None, "model_dir": MODEL_DIR})


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


_load_state()

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)))